.darma-loader-darma-custom-449 {color: var(--loader-color, #ca8a04);
   width: 65px;
   aspect-ratio: 1;
   --g: radial-gradient(farthest-side,#0000 calc(95% - 3px),currentColor calc(100% - 3px) 98%,#0000 101%) no-repeat;
   background: var(--g), var(--g), var(--g);
   background-size: 30px 30px;
   animation: darma-loader-darma-custom-449-l10 1.5s infinite;
}
@keyframes darma-loader-darma-custom-449-l10  {
  0%  {
  background-position: 0 0, 0 100%, 100% 100%;
}
25%  {
  background-position: 100% 0, 0 100%, 100% 100%;
}
50%  {
  background-position: 100% 0, 0 0, 100% 100%;
}
75%  {
  background-position: 100% 0, 0 0, 0 100%;
}
100%  {
  background-position: 100% 100%, 0 0, 0 100%;
}
}

